const body = $input.first().json.body || $input.first().json;
const accountId = body.account_id;
if (!accountId) throw new Error('account_id required');

// Determine input type
const isStructuredForm = body.business_hours || body.emergency_definition || body.emergency_routing_rules;
const source = body.source || 'onboarding_call';

return [{ json: { 
  account_id: accountId, 
  raw: body, 
  is_structured_form: isStructuredForm,
  source,
  transcript: body.transcript || ''
}}];

// Load v1 memo (in production: read from Supabase/storage by account_id)
// For n8n local: read from file system
const fs = require('fs');
const accountId = $('Normalize Onboarding Input').first().json.account_id;
const v1Path = `/tmp/clara/${accountId}/v1/account_memo.json`;

let v1Memo = {};
try {
  v1Memo = JSON.parse(fs.readFileSync(v1Path, 'utf8'));
} catch(e) {
  throw new Error(`No v1 memo found for ${accountId}. Run Pipeline A first.`);
}

// Get patch data (from form or LLM)
const patchData = $input.first().json;

// Smart merge: patch wins, null doesn't overwrite
function smartMerge(base, patch) {
  const result = JSON.parse(JSON.stringify(base));
  for (const [key, val] of Object.entries(patch)) {
    if (val === null || val === undefined) continue;
    if (typeof val === 'object' && !Array.isArray(val) && typeof result[key] === 'object') {
      result[key] = smartMerge(result[key] || {}, val);
    } else if (Array.isArray(val) && val.length > 0) {
      result[key] = val;
    } else if (!Array.isArray(val)) {
      result[key] = val;
    }
  }
  return result;
}

const v2Memo = smartMerge(v1Memo, patchData);
v2Memo.version = 'v2';
v2Memo.updated_at = new Date().toISOString();

// Build changelog
const changes = [];
for (const key of Object.keys(patchData)) {
  if (JSON.stringify(v1Memo[key]) !== JSON.stringify(v2Memo[key])) {
    changes.push({ field: key, old: v1Memo[key], new: v2Memo[key] });
  }
}

const changelog = {
  account_id: accountId,
  from_version: 'v1',
  to_version: 'v2',
  applied_at: new Date().toISOString(),
  changes
};

return [{ json: { v1_memo: v1Memo, v2_memo: v2Memo, changelog } }];
